// ============================================
// main.py 로직 반영
// ============================================

// === 데이터 가져오기 ===
const userData = $('지원자 로드').all().map(item => item.json);
const jobData = $('수시 채용공고 필터링').all().map(item => item.json);

// ============================================
// 상수 정의
// ============================================

const SortOption = {
  DEADLINE: "deadline",
  RECOMMENDATION: "recommend"
};

const FilterReason = {
  DEADLINE: "deadline",
  JOB: "job",
  EMPLOYMENT: "employment",
  COMPANY_SIZE: "company_size",
  INDUSTRY: "industry",
  EDUCATION: "education"
};

// ============================================
// 헬퍼 함수
// ============================================

function _splitCsv(s) {
  if (!s) return [];
  return String(s).split(",").map(x => x.trim()).filter(x => x);
}

function _normalizeIndustry(raw) {
  return raw.split("(")[0].trim();
}

function _parseIndustries(s) {
  if (!s) return [];

  const parts = [];
  let depth = 0;
  let current = [];

  for (const char of s) {
    if (char === "(") {
      depth++;
      current.push(char);
    } else if (char === ")") {
      depth--;
      current.push(char);
    } else if (char === "," && depth === 0) {
      const part = current.join("").trim();
      if (part) parts.push(_normalizeIndustry(part));
      current = [];
    } else {
      current.push(char);
    }
  }

  const part = current.join("").trim();
  if (part) parts.push(_normalizeIndustry(part));

  return parts;
}

function _normalizeSortValue(raw) {
  if (!raw) return "";
  const s = String(raw).toLowerCase();
  if (s.includes("마감")) return "deadline";
  if (s.includes("추천")) return "recommend";
  return "";
}

// ============================================
// 유저 정규화
// ============================================

function normalizeUser(record) {
  const f = (keyword) => {
    const key = Object.keys(record).find(k => k.includes(keyword));
    return key ? String(record[key] || "").trim() : "";
  };

  const top3Position = [f("1순위 희망"), f("2순위 희망"), f("3순위 희망")].filter(j => j);

  return {
    email: f("이메일 주소"),
    name: f("닉네임") || null,
    top3_position: top3Position,
    employment_type: _splitCsv(f("고용 형태")),
    education_level: _splitCsv(f("학력 정보")),
    company_size: _splitCsv(f("기업 규모")),
    company_industry: _parseIndustries(f("산업군")),
    has_language_score: f("영어 성적") || null,
    sort: _normalizeSortValue(f("정렬")),
    raw: record
  };
}
// ============================================
// 공고 어댑터
// ============================================

function adaptJob(src) {
  let processedPositionName = src.processed_position_name || [];
  if (typeof processedPositionName === 'string') {
    processedPositionName = processedPositionName ? [processedPositionName] : [];
  }

  let processedEmploymentType = src.processed_employment_type || [];
  if (typeof processedEmploymentType === 'string') {
    processedEmploymentType = processedEmploymentType ? [processedEmploymentType] : [];
  }

  let processedEducationLevelList = src.processed_education_level || [];
  if (typeof processedEducationLevelList === 'string') {
    processedEducationLevelList = processedEducationLevelList ? [processedEducationLevelList] : [];
  }

  let deadline = null;
  let deadlineDate = null;
  if (src.deadline_date) {
    try {
      deadline = new Date(src.deadline_date);
      if (isNaN(deadline.getTime())) {
        deadline = null;
      } else {
        deadlineDate = new Date(deadline);
        deadlineDate.setHours(0, 0, 0, 0);
      }
    } catch (e) {
      deadline = null;
    }
  }

  // processed_language_required: boolean 변환
  let languageRequired = false;
  if (src.processed_language_required) {
    const val = String(src.processed_language_required).toLowerCase();
    languageRequired = (val === "true" || val === "1" || val === "yes" || val === "예");
  }

  return {
    company_name: src.company_name || "",
    job_title: src.job_title || "",
    job_url: src.job_url || "",
    processed_position_name: processedPositionName,
    processed_employment_type: processedEmploymentType,
    processed_education_level_list: processedEducationLevelList,
    processed_experience_level: src.processed_experience_level || "",
    processed_language_required: languageRequired,  // boolean
    industry: src.company_industry || null,
    company_size: src.company_size || null,
    application_deadline_date: src.deadline_date || null,
    application_deadline_time: src.deadline_time || null,
    deadline,
    deadline_date_only: deadlineDate,
    raw: src
  };
}

// ============================================
// 필터 함수들 (Python filter.py와 동일)
// ============================================

/**
 * 1. 마감일 하드 필터
 * - mindate < deadline_date <= mindate + 30일
 * - 마감일 없으면 통과
 */
function _deadlineFilter(jobs, referenceDate = null) {
  const today = referenceDate ? new Date(referenceDate) : new Date();
  today.setHours(0, 0, 0, 0);

  // minDate는 send_date와 동일. 이때 send_Date는 today + 1일
  // 따라서 minDate = send_date = today + 1
  const minDate = new Date(today);
  minDate.setDate(minDate.getDate() + 1);
  const maxDate = new Date(minDate);
  maxDate.setDate(maxDate.getDate() + 31);

  return jobs.filter(j => {
    if (!j.deadline_date_only) return true;
    try {
      const d = j.deadline_date_only;
      return d > minDate && d <= maxDate;
    } catch (e) {
      return true;
    }
  });
}

/**
 * 2. 직무 하드 필터
 */
function _positionFilter(user, jobs) {
  if (!user.top3_position || user.top3_position.length === 0) return jobs;
  return jobs.filter(j => 
    j.processed_position_name.some(pos => user.top3_position.includes(pos))
  );
}

/**
 * 3. 학력 하드 필터
 */

function mapEducationLevel(s) {
  if (!s) return "";
  if (s.includes("박사")) return "박사";
  if (s.includes("석사")) return "석사";
  if (s.includes("전문")) return "전문학사";
  if (s.includes("학사")) return "학사";
  if (s.includes("학력무관")) return "학력무관";
  return "";
}

function _educationFilter(user, jobs) {
  if (!user.education_level || user.education_level.length === 0) return jobs;

  const userEduKeywords = new Set();
  for (const edu of user.education_level) {
    const kw = mapEducationLevel(edu);
    if (kw) userEduKeywords.add(kw);
  }
  if (userEduKeywords.size === 0) return jobs;

  return jobs.filter(j => {
    if (!j.processed_education_level_list || j.processed_education_level_list.length === 0) return true;

    // job의 학력 키워드 정리
    const jobEduKeywords = new Set();
    for (const edu of j.processed_education_level_list) {
      const kw = mapEducationLevel(edu);
      if (kw) jobEduKeywords.add(kw);
    }

    if (jobEduKeywords.has("학력무관")) return true;

    // user 값이 job의 학력 키워드에 부분 포함이라면 통과
    for (const kw of jobEduKeywords) {
      if (userEduKeywords.has(kw)) return true;
    }
    return false;
  });
}

/**
 * 4. 어학점수 하드 필터
 * - 유저가 어학점수 보유("예") → 전부 통과
 * - 유저가 미보유("아니오")인데 공고가 어학 필수 → 제거
 */
function _languageScoreFilter(user, jobs) {
  // 유저가 어학점수 보유하면 전부 통과
  if (user.has_language_score === "예") {
    return jobs;
  }
  // 유저가 "아니오"인 경우: 어학 필수 공고 제거
  return jobs.filter(j => !j.processed_language_required);
}

/**
 * 5. 경력 하드 필터
 * - 경력직만 모집하는 공고 제거 (신입/경력무관은 통과)
 */
function _experienceLevelFilter(jobs) {
  return jobs.filter(j => j.processed_experience_level !== "경력");
}

// ============================================
// 소프트 감사 필터 (고용형태, 기업규모, 산업)
// ============================================

function _employmentTypeAudit(user, jobs) {
  const failed = new Map();
  if (!user.employment_type || user.employment_type.length === 0) return failed;

  for (const j of jobs) {
    if (!j.processed_employment_type || j.processed_employment_type.length === 0) continue;
    if (!j.processed_employment_type.some(emp => user.employment_type.includes(emp))) {
      failed.set(j, FilterReason.EMPLOYMENT);
    }
  }
  return failed;
}

function _companySizeAudit(user, jobs) {
  const failed = new Map();
  if (!user.company_size || user.company_size.length === 0) return failed;

  for (const j of jobs) {
    if (j.company_size && !user.company_size.includes(j.company_size)) {
      failed.set(j, FilterReason.COMPANY_SIZE);
    }
  }
  return failed;
}

function _industryAudit(user, jobs) {
  const failed = new Map();
  if (!user.company_industry || user.company_industry.length === 0) return failed;

  for (const j of jobs) {
    if (j.industry && !user.company_industry.includes(j.industry)) {
      failed.set(j, FilterReason.INDUSTRY);
    }
  }
  return failed;
}

function _buildAudit(jobs, ...partialAudits) {
  const combined = new Map();
  for (const j of jobs) {
    combined.set(j, new Set());
  }
  for (const partial of partialAudits) {
    for (const [job, reason] of partial) {
      if (combined.has(job)) {
        combined.get(job).add(reason);
      }
    }
  }
  return combined;
}

/**
 * 필터 전체 적용 (Python filter.py와 동일한 순서)
 * 
 * 하드 필터 순서:
 * 1. 마감일 → 2. 직무 → 3. 학력 → 4. 어학점수 → 5. 경력
 * 
 * 소프트 감사:
 * 고용형태 / 기업규모 / 산업
 */
function applyFilters(user, jobs, referenceDate = null) {
  // 1단계: 하드 필터
  let candidates = _deadlineFilter(jobs, referenceDate);
  candidates = _positionFilter(user, candidates);
  candidates = _educationFilter(user, candidates);
  candidates = _languageScoreFilter(user, candidates);
  candidates = _experienceLevelFilter(candidates);

  // 2단계: 소프트 감사
  const audit = _buildAudit(
    candidates,
    _employmentTypeAudit(user, candidates),
    _companySizeAudit(user, candidates),
    _industryAudit(user, candidates)
  );

  return { audit, candidates };
}

// ============================================
// 추천 함수들
// ============================================

function _getJobPriorityRank(job, user) {
  if (!user.top3_position || !job.processed_position_name) return null;

  for (let rank = 0; rank < user.top3_position.length && rank < 3; rank++) {
    const targetJob = user.top3_position[rank];
    if (!targetJob) continue;
    if (job.processed_position_name.includes(targetJob)) {
      return rank + 1;
    }
  }
  return null;
}

function recommendPersonalized(user, filterResult, sort) {
  const items = [];

  for (const [job, reasons] of filterResult.audit) {
    if (reasons.size === 0) {
      const rank = _getJobPriorityRank(job, user);
      items.push({ job, job_priority_rank: rank });
    }
  }

  if (sort === SortOption.DEADLINE) {
    items.sort((a, b) => {
      const aNull = a.job.deadline === null;
      const bNull = b.job.deadline === null;
      if (aNull && bNull) return 0;
      if (aNull) return 1;
      if (bNull) return -1;
      return a.job.deadline - b.job.deadline;
    });
  } else {
    items.sort((a, b) => {
      const rankA = a.job_priority_rank !== null ? a.job_priority_rank : 4;
      const rankB = b.job_priority_rank !== null ? b.job_priority_rank : 4;
      if (rankA !== rankB) return rankA - rankB;

      const aNull = a.job.deadline === null;
      const bNull = b.job.deadline === null;
      if (aNull && bNull) return 0;
      if (aNull) return 1;
      if (bNull) return -1;
      return a.job.deadline - b.job.deadline;
    });
  }

  return items.slice(0, 25);
}

function recommendExplore(filterResult) {
  const SOFT_REASONS = new Set([FilterReason.EMPLOYMENT, FilterReason.COMPANY_SIZE, FilterReason.INDUSTRY]);
  const ranked = [];

  for (const [job, reasons] of filterResult.audit) {
    let softCount = 0;
    for (const r of reasons) {
      if (SOFT_REASONS.has(r)) softCount++;
    }
    if (softCount > 0) {
      ranked.push({ job, softCount });
    }
  }

  ranked.sort((a, b) => a.softCount - b.softCount);
  return ranked.slice(0, 5).map(item => ({ job: item.job, job_priority_rank: null }));
}

// ============================================
// 메인 실행
// ============================================

const users_normalized = userData.map(r => normalizeUser(r));
const jobs = jobData.map(d => adaptJob(d));

const allResults = [];

for (let i = 0; i < users_normalized.length; i++) {
  const u = users_normalized[i];
  const sort = u.sort === "deadline" ? SortOption.DEADLINE : SortOption.RECOMMENDATION;

  const filterResult = applyFilters(u, jobs);
  const personalizedRecs = recommendPersonalized(u, filterResult, sort);
  const exploreRecs = recommendExplore(filterResult);

  function _buildRecList(recs) {
    return recs.map((item, idx) => {
      const j = item.job;
      return {
        rank: idx + 1,
        job_priority_rank: item.job_priority_rank,
        company_name: j.company_name,
        job_title: j.job_title,
        job_url: j.job_url,
        position_name: j.processed_position_name,
        employment_type: j.processed_employment_type,
        education_level: j.processed_education_level_list,
        experience_level: j.processed_experience_level,
        language_required: j.processed_language_required,
        company_size: j.company_size,
        industry: j.industry,
        deadline_date: j.application_deadline_date,
        deadline_time: j.application_deadline_time,
      };
    });
  }

  const pRecs = _buildRecList(personalizedRecs);
  let eRecs = _buildRecList(exploreRecs);

  // 전문연 후처리: 유저가 전문연 미선택 시 전문연 포함 공고 제거
  if (!u.employment_type.includes("전문연")) {
    eRecs = eRecs.filter(rec => !rec.employment_type.includes("전문연"));
  }

  const recTime = new Date().toLocaleString("ko-KR", { timeZone: "Asia/Seoul" });

  allResults.push({
    json: {
      email: u.email,
      name: u.name,
      sort_method: sort,
      filter_criteria: {
        target_jobs: u.top3_position,
        target_employment_types: u.employment_type,
        current_education: u.education_level,
        preferred_company_sizes: u.company_size,
        interested_industries: u.company_industry,
        has_english_score: u.has_language_score,
      },
      personalized_total: pRecs.length,
      personalized_recommendations: pRecs,
      explore_total: eRecs.length,
      explore_recommendations: eRecs,
      rec_time: recTime,
    }
  });
}

return allResults;

// [데이터 평탄화] URL 중복 제거 + 필드 병합 버전 (이중 배열)
const allRows = [];
const inputList = $input.all();

// URL 기준 병합을 적용할 기업명 화이트리스트
const MERGE_COMPANIES = ["네이버"];

// 단일값을 배열로 안전하게 변환
function toArray(val) {
  if (Array.isArray(val)) return val;
  if (val === null || val === undefined || val === "") return [];
  return [val];
}

// 단일 배열로 초기화된 항목을 이중 배열로 업그레이드
function upgradeToNested(existing) {
  existing.position_names   = [existing.position_names];
  existing.education_levels = [existing.education_levels];
  existing.experience_levels = [existing.experience_levels];
  existing.employment_types  = [existing.employment_types];
  existing.language_requireds = [existing.language_requireds];
  existing._isNested = true;
}

// 기존 항목에 새 공고를 이중 배열 방식으로 병합
function mergeInto(existing, rec) {
  if (!existing._isNested) upgradeToNested(existing);
  existing.ranks.push(rec.rank);
  existing.position_names.push(toArray(rec.position_name));
  existing.education_levels.push(toArray(rec.education_level));
  existing.experience_levels.push(rec.experience_level || "");
  existing.employment_types.push(toArray(rec.employment_type));
  existing.language_requireds.push(rec.language_required || "");
  if (rec.deadline_date && (!existing.deadline_date || rec.deadline_date < existing.deadline_date)) {
    existing.deadline_date = rec.deadline_date;
    existing.deadline_time = rec.deadline_time || null;
  }
}

// URL 기준으로 공고 목록을 그룹화하여 병합
function mergeByUrl(recs, sortMethod) {
  const urlMap = new Map();

  for (const rec of recs) {
    const url = rec.job_url || rec.url || "";
    const isMultiCompany = MERGE_COMPANIES.includes(rec.company_name);
    const mergeKey = isMultiCompany
      ? url
      : `${rec.company_name}__${url}`;

    if (!urlMap.has(mergeKey)) {
      // 항상 단일 배열로 초기화 (중복이 생기면 mergeInto에서 이중 배열로 업그레이드)
      urlMap.set(mergeKey, {
        company_name:       rec.company_name || "",
        job_title:          rec.job_title || "",
        job_url:            url,
        deadline_date:      rec.deadline_date || rec.deadline || null,
        deadline_time:      rec.deadline_time || null,
        company_size:       rec.company_size || "",
        industry:           rec.industry || "",
        _isNested:          false,
        ranks:              [rec.rank],
        position_names:     toArray(rec.position_name),
        education_levels:   toArray(rec.education_level),
        experience_levels:  rec.experience_level || "",
        employment_types:   toArray(rec.employment_type),
        language_requireds: rec.language_required || "",
      });
    } else {
      // 중복 진입: MERGE_COMPANIES 의도적 중복이든 예외 중복이든 동일하게 이중 배열로 병합
      mergeInto(urlMap.get(mergeKey), rec);
    }
  }

  // 정렬
  const merged = Array.from(urlMap.values());
  merged.sort((a, b) => {
    if (sortMethod === "deadline") {
      const aRank = Math.min(...a.ranks);
      const bRank = Math.min(...b.ranks);
      if (!a.deadline_date && !b.deadline_date) return aRank - bRank;
      if (!a.deadline_date) return 1;
      if (!b.deadline_date) return -1;
      return a.deadline_date < b.deadline_date ? -1 : a.deadline_date > b.deadline_date ? 1 : 0;
    } else {
      const aRank = Math.min(...a.ranks);
      const bRank = Math.min(...b.ranks);
      return aRank - bRank;
    }
  });

  return merged;
}

for (let i = 0; i < inputList.length; i++) {
  const data = inputList[i].json;

  const sortMethod      = data.sort_method || "";
  const email           = data.email || "";
  const name            = data.name || "";
  const rec_time        = data.rec_time || "";
  const user_condition  = data.filter_criteria || {};
  const personalized    = data.personalized_recommendations || [];
  const explore         = data.explore_recommendations || [];

  const totalCount = (data.personalized_total || 0) + (data.explore_total || 0);

  const mergedPersonalized = mergeByUrl(personalized, sortMethod);
  const mergedExplore      = mergeByUrl(explore, sortMethod);

  // personalized 평탄화
  for (const rec of mergedPersonalized) {
    allRows.push({
      json: {
        "추천일자":                       rec_time,
        "닉네임":                         name,
        "이메일":                         email,
        "추천 기업명 (company_name)":      rec.company_name,
        "추천 공고명 (job_title)":         rec.job_title,
        "레이어 구분":                    "맞춤형",
        "정렬 구분":                      sortMethod === "deadline" ? "마감순" : "추천순",
        "rank":                           rec.ranks,
        "유저 당 총 추천개수":             totalCount,
        "채용공고URL (job_url)":          rec.job_url,
        "마감기한 일자 (deadline_date)":   rec.deadline_date || "",
        "마감기한 시간 (deadline_time)":   rec.deadline_time || "",
        "job_company_size":               rec.company_size,
        "job_company_industry":           rec.industry,
        "job_processed_position_name":    rec.position_names,
        "job_processed_education_level":  rec.education_levels,
        "job_processed_experience_level": rec.experience_levels,
        "job_processed_employment_type":  rec.employment_types,
        "job_processed_language_required": rec.language_required ?? false,
        "user_company_size":              user_condition.preferred_company_sizes || [],
        "user_company_industry":          user_condition.interested_industries   || [],
        "user_top3_position":             [...new Set(user_condition.target_jobs || [])],
        "user_education_level":           user_condition.current_education       || [],
        "user_employment_type":           user_condition.target_employment_types || [],
        "user_has_language_score":        user_condition.has_english_score       || "",
      }
    });
  }

  // explore 평탄화
  for (const rec of mergedExplore) {
    allRows.push({
      json: {
        "추천일자":                       rec_time,
        "닉네임":                         name,
        "이메일":                         email,
        "추천 기업명 (company_name)":      rec.company_name,
        "추천 공고명 (job_title)":         rec.job_title,
        "레이어 구분":                    "탐색형",
        "정렬 구분":                      "",
