// ============================================
// 헬퍼 함수
// ============================================

function _splitCsv(s) {
  if (!s) return [];
  return String(s).split(",").map(x => x.trim()).filter(x => x);
}

function _normalizeIndustry(raw) {
  return raw.split("(")[0].trim();
}

function _parseIndustries(s) {
  if (!s) return [];

  const parts = [];
  let depth = 0;
  let current = [];

  for (const char of s) {
    if (char === "(") {
      depth++;
      current.push(char);
    } else if (char === ")") {
      depth--;
      current.push(char);
    } else if (char === "," && depth === 0) {
      const part = current.join("").trim();
      if (part) parts.push(_normalizeIndustry(part));
      current = [];
    } else {
      current.push(char);
    }
  }

  const part = current.join("").trim();
  if (part) parts.push(_normalizeIndustry(part));

  return parts;
}

function _normalizeSortValue(raw) {
  if (!raw) return "";
  const s = String(raw).toLowerCase();
  if (s.includes("마감")) return "deadline";
  if (s.includes("추천")) return "recommend";
  return "";
}

