function adaptJob(src) {
  let processedPositionName = src.processed_position_name || [];
  if (typeof processedPositionName === 'string') {
    processedPositionName = processedPositionName ? [processedPositionName] : [];
  }

  let processedEmploymentType = src.processed_employment_type || [];
  if (typeof processedEmploymentType === 'string') {
    processedEmploymentType = processedEmploymentType ? [processedEmploymentType] : [];
  }

  let processedEducationLevelList = src.processed_education_level || [];
  if (typeof processedEducationLevelList === 'string') {
    processedEducationLevelList = processedEducationLevelList ? [processedEducationLevelList] : [];
  }

  let deadline = null;
  let deadlineDate = null;
  if (src.deadline_date) {
    try {
      deadline = new Date(src.deadline_date);
      if (isNaN(deadline.getTime())) {
        deadline = null;
      } else {
        deadlineDate = new Date(deadline);
        deadlineDate.setHours(0, 0, 0, 0);
      }
    } catch (e) {
      deadline = null;
    }
  }

  // processed_language_required: boolean 변환
  let languageRequired = false;
  if (src.processed_language_required) {
    const val = String(src.processed_language_required).toLowerCase();
    languageRequired = (val === "true" || val === "1" || val === "yes" || val === "예");
  }

  return {
    company_name: src.company_name || "",
    job_title: src.job_title || "",
    job_url: src.job_url || "",
    processed_position_name: processedPositionName,
    processed_employment_type: processedEmploymentType,
