    processed_language_required: languageRequired,  // boolean
    industry: src.industry || null,
    company_size: src.company_size || null,
    application_deadline_date: src.deadline_date || null,
    application_deadline_time: src.deadline_time || null,
    deadline,
    deadline_date_only: deadlineDate,
    raw: src
  };
}

// ============================================
// 필터 함수들 (Python filter.py와 동일)
// ============================================

/**
 * 1. 마감일 하드 필터
 * - today < deadline_date <= today + 30일
 * - 마감일 없으면 통과
 */
function _deadlineFilter(jobs, referenceDate = null) {
  const today = referenceDate ? new Date(referenceDate) : new Date();
  today.setHours(0, 0, 0, 0);

  // minDate는 send_date와 동일. 이때 send_Date는 today + 1일
  // 따라서 minDate = send_date = today + 1
  const minDate = new Date(today);
  minDate.setDate(minDate.getDate() + 1);
  const maxDate = new Date(minDate);
  maxDate.setDate(maxDate.getDate() + 31);

  return jobs.filter(j => {
    if (!j.deadline_date_only) return true;
    try {
      const d = j.deadline_date_only;
      return d > minDate && d <= maxDate;
    } catch (e) {
      return true;
    }
  });
}

/**
 * 2. 직무 하드 필터
 */
function _positionFilter(user, jobs) {
  if (!user.top3_position || user.top3_position.length === 0) return jobs;
  return jobs.filter(j => 
    j.processed_position_name.some(pos => user.top3_position.includes(pos))
  );
}

/**
 * 3. 학력 하드 필터
 */

function mapEducationLevel(s) {
  if (!s) return "";
  if (s.includes("박사")) return "박사";
  if (s.includes("석사")) return "석사";
  if (s.includes("학사")) return "학사";
  if (s.includes("학력무관")) return "학력무관";
  return "";
}

function _educationFilter(user, jobs) {
  if (!user.education_level || user.education_level.length === 0) return jobs;

  const userEduKeywords = new Set();
  for (const edu of user.education_level) {
    const kw = mapEducationLevel(edu);
    if (kw) userEduKeywords.add(kw);
  }
  if (userEduKeywords.size === 0) return jobs;

  return jobs.filter(j => {
    if (!j.processed_education_level_list || j.processed_education_level_list.length === 0) return true;

    // job의 학력 키워드 정리
    const jobEduKeywords = new Set();
    for (const edu of j.processed_education_level_list) {
      const kw = mapEducationLevel(edu);
      if (kw) jobEduKeywords.add(kw);
    }

    if (jobEduKeywords.has("학력무관")) return true;

    // user 값이 job의 학력 키워드에 부분 포함이라면 통과
    for (const kw of jobEduKeywords) {
      if (userEduKeywords.has(kw)) return true;
    }
    return false;
  });
}

/**
 * 4. 어학점수 하드 필터
 * - 유저가 어학점수 보유("예") → 전부 통과
 * - 유저가 미보유("아니오")인데 공고가 어학 필수 → 제거
 */
function _languageScoreFilter(user, jobs) {
  // 유저가 어학점수 보유하면 전부 통과
  if (user.has_language_score === "예") {
    return jobs;
  }
  // 유저가 "아니오"인 경우: 어학 필수 공고 제거
  return jobs.filter(j => !j.processed_language_required);
}

/**
 * 5. 경력 하드 필터
 * - 경력직만 모집하는 공고 제거 (신입/경력무관은 통과)
 */
function _experienceLevelFilter(jobs) {
  return jobs.filter(j => j.processed_experience_level !== "경력");
}

// ============================================
// 소프트 감사 필터 (고용형태, 기업규모, 산업)
// ============================================

function _employmentTypeAudit(user, jobs) {
  const failed = new Map();
  if (!user.employment_type || user.employment_type.length === 0) return failed;

  for (const j of jobs) {
    if (!j.processed_employment_type || j.processed_employment_type.length === 0) continue;
    if (!j.processed_employment_type.some(emp => user.employment_type.includes(emp))) {
      failed.set(j, FilterReason.EMPLOYMENT);
    }
  }
  return failed;
}

function _companySizeAudit(user, jobs) {
  const failed = new Map();
  if (!user.company_size || user.company_size.length === 0) return failed;

  for (const j of jobs) {
    if (j.company_size && !user.company_size.includes(j.company_size)) {
      failed.set(j, FilterReason.COMPANY_SIZE);
    }
  }
  return failed;
}

function _industryAudit(user, jobs) {
  const failed = new Map();
  if (!user.company_industry || user.company_industry.length === 0) return failed;

  for (const j of jobs) {
    if (j.industry && !user.company_industry.includes(j.industry)) {
      failed.set(j, FilterReason.INDUSTRY);
    }
  }
  return failed;
}

function _buildAudit(jobs, ...partialAudits) {
  const combined = new Map();
  for (const j of jobs) {
    combined.set(j, new Set());
  }
  for (const partial of partialAudits) {
    for (const [job, reason] of partial) {
      if (combined.has(job)) {
        combined.get(job).add(reason);
      }
    }
  }
  return combined;
}

/**
 * 필터 전체 적용 (Python filter.py와 동일한 순서)
 * 
 * 하드 필터 순서:
 * 1. 마감일 → 2. 직무 → 3. 학력 → 4. 어학점수 → 5. 경력
 * 
 * 소프트 감사:
 * 고용형태 / 기업규모 / 산업
 */
function applyFilters(user, jobs, referenceDate = null) {
  // 1단계: 하드 필터
  let candidates = _deadlineFilter(jobs, referenceDate);
  candidates = _positionFilter(user, candidates);
  candidates = _educationFilter(user, candidates);
  candidates = _languageScoreFilter(user, candidates);  // 신규 추가
  candidates = _experienceLevelFilter(candidates);       // 신규 추가

  // 2단계: 소프트 감사
  const audit = _buildAudit(
    candidates,
    _employmentTypeAudit(user, candidates),
    _companySizeAudit(user, candidates),
    _industryAudit(user, candidates)
  );

  return { audit, candidates };
}

