function _getJobPriorityRank(job, user) {
  if (!user.top3_position || !job.processed_position_name) return null;

  for (let rank = 0; rank < user.top3_position.length && rank < 3; rank++) {
    const targetJob = user.top3_position[rank];
    if (!targetJob) continue;
    if (job.processed_position_name.includes(targetJob)) {
      return rank + 1;
    }
  }
  return null;
}

function recommendPersonalized(user, filterResult, sort) {
  const items = [];

  for (const [job, reasons] of filterResult.audit) {
    if (reasons.size === 0) {
      const rank = _getJobPriorityRank(job, user);
      items.push({ job, job_priority_rank: rank });
    }
  }

  if (sort === SortOption.DEADLINE) {
    items.sort((a, b) => {
      const aNull = a.job.deadline === null;
      const bNull = b.job.deadline === null;
      if (aNull && bNull) return 0;
      if (aNull) return 1;
      if (bNull) return -1;
      return a.job.deadline - b.job.deadline;
    });
  } else {
    items.sort((a, b) => {
      const rankA = a.job_priority_rank !== null ? a.job_priority_rank : 4;
      const rankB = b.job_priority_rank !== null ? b.job_priority_rank : 4;
      if (rankA !== rankB) return rankA - rankB;

      const aNull = a.job.deadline === null;
      const bNull = b.job.deadline === null;
      if (aNull && bNull) return 0;
      if (aNull) return 1;
      if (bNull) return -1;
      return a.job.deadline - b.job.deadline;
    });
  }

  return items.slice(0, 25);
}

const ALL_POSITIONS = ["AI기획자", "AI리서치", "데이터분석가", "데이터엔지니어", "ML엔지니어"];

function recommendExplore(user, jobs, filterResult, referenceDate = null) {
  const SOFT_REASONS = new Set([FilterReason.EMPLOYMENT, FilterReason.COMPANY_SIZE, FilterReason.INDUSTRY]);

  // 1차: 기존 방식
  const ranked = [];
  for (const [job, reasons] of filterResult.audit) {
    let softCount = 0;
    for (const r of reasons) {
      if (SOFT_REASONS.has(r)) softCount++;
    }
    if (softCount > 0) {
      ranked.push({ job, softCount });
    }
  }

  if (ranked.length > 0) {
    ranked.sort((a, b) => a.softCount - b.softCount);
    return ranked.slice(0, 5).map(item => ({ job: item.job, job_priority_rank: null }));
  }

  // 2차: 나머지 직무로 확장 탐색
  const otherPositions = ALL_POSITIONS.filter(p => !user.top3_position.includes(p));
  if (otherPositions.length === 0) return [];

  let exploreCandidates = _deadlineFilter(jobs, referenceDate);
  exploreCandidates = exploreCandidates.filter(j =>
    j.processed_position_name.some(pos => otherPositions.includes(pos))
  );
  exploreCandidates = _educationFilter(user, exploreCandidates);
  exploreCandidates = _languageScoreFilter(user, exploreCandidates);
  exploreCandidates = _experienceLevelFilter(exploreCandidates);

  // 소프트 감사 재실행
  const exploreAudit = _buildAudit(
    exploreCandidates,
    _employmentTypeAudit(user, exploreCandidates),
    _companySizeAudit(user, exploreCandidates),
    _industryAudit(user, exploreCandidates)
  );

  const ranked2 = [];
  for (const [job, reasons] of exploreAudit) {
    let softCount = 0;
    for (const r of reasons) {
      if (SOFT_REASONS.has(r)) softCount++;
    }
    ranked2.push({ job, softCount });  // softCount = 0도 포함
  }

  ranked2.sort((a, b) => a.softCount - b.softCount);
  return ranked2.slice(0, 5).map(item => ({ job: item.job, job_priority_rank: null }));
}

